
BEGIN TRANSACTION;

CREATE TABLE IF NOT EXISTS "infraestrutura_pasto" ("id" integer NOT NULL PRIMARY KEY , "nome" varchar(100) NOT NULL UNIQUE, "area_hectares" decimal NOT NULL, "tipo_capim" varchar(100) NOT NULL, "data_ultimo_manejo" date NULL, "observacoes" text NULL, "capacidade_maxima_ua" integer NULL);
CREATE TABLE IF NOT EXISTS "rebanho_animal" ("id" integer NOT NULL PRIMARY KEY , "identificacao" varchar(50) NOT NULL UNIQUE, "nome" varchar(100) NULL, "data_nascimento" date NOT NULL, "sexo" varchar(1) NOT NULL, "situacao" varchar(10) NOT NULL, "observacoes" text NOT NULL, "mae_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "pai_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "pasto_atual_id" bigint NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED, "lote_atual_id" bigint NULL REFERENCES "rebanho_lote" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "rebanho_baixaanimal" ("id" integer NOT NULL PRIMARY KEY , "data_baixa" date NOT NULL, "causa" varchar(10) NOT NULL, "observacoes" text NULL, "animal_id" bigint NOT NULL UNIQUE REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "rebanho_lote" ("id" integer NOT NULL PRIMARY KEY , "nome" varchar(100) NOT NULL UNIQUE, "data_entrada" date NOT NULL, "finalidade" varchar(50) NOT NULL, "pasto_atual_id" bigint NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "infraestrutura_movimentacaopasto" ("id" integer NOT NULL PRIMARY KEY , "data_entrada" date NOT NULL, "data_saida" date NULL, "motivo" varchar(255) NULL, "animal_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "pasto_destino_id" bigint NOT NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED, "pasto_origem_id" bigint NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" timestamp NOT NULL);
CREATE TABLE IF NOT EXISTS "financeiro_categoriadespesa" ("id" integer NOT NULL PRIMARY KEY , "nome" varchar(100) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "financeiro_categoriareceita" ("id" integer NOT NULL PRIMARY KEY , "nome" varchar(100) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "financeiro_fluxosaida" ("id" integer NOT NULL PRIMARY KEY , "data_pagamento" date NOT NULL, "descricao" varchar(255) NOT NULL, "valor_total" decimal NOT NULL, "tipo_saida" varchar(15) NOT NULL, "observacoes" text NULL);
CREATE TABLE IF NOT EXISTS "financeiro_fluxoentrada" ("id" integer NOT NULL PRIMARY KEY , "data_entrada" date NOT NULL, "descricao" varchar(255) NOT NULL, "valor_total" decimal NOT NULL, "origem_pagador" varchar(255) NOT NULL, "tipo_entrada" varchar(15) NOT NULL, "observacoes" text NULL);
CREATE TABLE IF NOT EXISTS "financeiro_tipocusto" ("id" integer NOT NULL PRIMARY KEY , "nome" varchar(100) NOT NULL UNIQUE, "descricao" text NULL);
CREATE TABLE IF NOT EXISTS "financeiro_registrodecusto" ("fluxosaida_ptr_id" bigint NOT NULL PRIMARY KEY REFERENCES "financeiro_fluxosaida" ("id") DEFERRABLE INITIALLY DEFERRED, "quantidade" decimal NOT NULL, "animal_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "pasto_id" bigint NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED, "tipo_custo_id" bigint NOT NULL REFERENCES "financeiro_tipocusto" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "financeiro_despesa" ("fluxosaida_ptr_id" bigint NOT NULL PRIMARY KEY REFERENCES "financeiro_fluxosaida" ("id") DEFERRABLE INITIALLY DEFERRED, "tipo" varchar(10) NOT NULL, "categoria_id" bigint NOT NULL REFERENCES "financeiro_categoriadespesa" ("id") DEFERRABLE INITIALLY DEFERRED, "registro_de_custo_id" bigint NULL UNIQUE REFERENCES "financeiro_registrodecusto" ("fluxosaida_ptr_id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "financeiro_receitageral" ("fluxoentrada_ptr_id" bigint NOT NULL PRIMARY KEY REFERENCES "financeiro_fluxoentrada" ("id") DEFERRABLE INITIALLY DEFERRED, "categoria_id" bigint NOT NULL REFERENCES "financeiro_categoriareceita" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "financeiro_venda" ("fluxoentrada_ptr_id" bigint NOT NULL PRIMARY KEY REFERENCES "financeiro_fluxoentrada" ("id") DEFERRABLE INITIALLY DEFERRED, "peso_venda" decimal NULL, "animal_id" bigint NOT NULL UNIQUE REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "financeiro_custoanimaldetalhe" ("id" integer NOT NULL PRIMARY KEY , "valor_alocado" decimal NOT NULL, "animal_id" bigint NOT NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "registro_de_custo_id" bigint NOT NULL REFERENCES "financeiro_registrodecusto" ("fluxosaida_ptr_id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "manejo_pesagem" ("id" integer NOT NULL PRIMARY KEY , "data_pesagem" date NOT NULL, "peso_kg" decimal NOT NULL, "evento" varchar(50) NOT NULL, "animal_id" bigint NOT NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "manejo_reproducao" ("id" integer NOT NULL PRIMARY KEY , "data_cio" date NOT NULL, "escore" decimal NULL, "tipo" varchar(20) NOT NULL, "codigo_semen" varchar(50) NOT NULL, "data_dg" date NULL, "resultado" varchar(10) NOT NULL, "data_parto_prevista" date NULL, "bezerro_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "matriz_id" bigint NOT NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "touro_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "manejo_tarefamanejo" ("id" integer NOT NULL PRIMARY KEY , "titulo" varchar(200) NOT NULL, "data_prevista" date NOT NULL, "tipo" varchar(2) NOT NULL, "descricao" text NULL, "concluida" bool NOT NULL, "animal_id" bigint NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED, "pasto_id" bigint NULL REFERENCES "infraestrutura_pasto" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "manejo_tratamentosaude" ("id" integer NOT NULL PRIMARY KEY , "data_tratamento" date NOT NULL, "tipo_tratamento" varchar(4) NOT NULL, "produto" varchar(100) NOT NULL, "dose" varchar(50) NOT NULL, "descricao" text NOT NULL, "data_proximo_tratamento" date NULL, "animal_id" bigint NOT NULL REFERENCES "rebanho_animal" ("id") DEFERRABLE INITIALLY DEFERRED);
